const express = require('express');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const redis = require('redis');

const app = express();

// CRITICAL: Configure Express to trust only specific proxies
// Set to the number of proxy hops (e.g., 1 for single load balancer)
app.set('trust proxy', 1); // Or use specific IPs: ['10.0.0.1', '172.16.0.1']

// Create Redis client for distributed rate limiting
const redisClient = redis.createClient({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD,
  enable_offline_queue: false
});

redisClient.on('error', (err) => {
  console.error('Redis connection error:', err);
});

// Custom key generator using validated client IP
const keyGenerator = (req) => {
  // Express extracts the client IP from trusted proxies
  // This respects the 'trust proxy' setting
  const clientIp = req.ip; // This is safe after trust proxy configuration

  // Optional: Add additional context (e.g., user ID for authenticated endpoints)
  const userId = req.user?.id || 'anonymous';

  return `${clientIp}:${userId}`;
};

// General API rate limiter
const apiLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:api:',
  }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  standardHeaders: true, // Return rate limit info in `RateLimit-*` headers
  legacyHeaders: false, // Disable `X-RateLimit-*` headers
  keyGenerator: keyGenerator,
  handler: (req, res) => {
    res.status(429).json({
      error: 'Too many requests',
      message: 'You have exceeded the rate limit. Please try again later.',
      retryAfter: req.rateLimit.resetTime
    });
  },
  // Skip rate limiting for health checks
  skip: (req) => req.path === '/health'
});

// Stricter rate limiter for authentication endpoints
const authLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:auth:',
  }),
  windowMs: 15 * 60 * 1000,
  max: 5, // Only 5 login attempts per 15 minutes
  skipSuccessfulRequests: true, // Don't count successful logins
  keyGenerator: keyGenerator,
  handler: (req, res) => {
    console.warn(`Rate limit exceeded for IP: ${req.ip}`);
    res.status(429).json({
      error: 'Too many authentication attempts',
      message: 'Account temporarily locked. Please try again in 15 minutes.',
      retryAfter: req.rateLimit.resetTime
    });
  }
});

// Apply rate limiters
app.use('/api/', apiLimiter); // General API rate limiting
app.post('/api/login', authLimiter, (req, res) => {
  // Authentication logic
  res.json({ message: 'Login successful' });
});

app.post('/api/register', authLimiter, (req, res) => {
  // Registration logic
  res.json({ message: 'Registration successful' });
});

// Middleware to log suspicious header manipulation attempts
app.use((req, res, next) => {
  const suspiciousHeaders = ['x-forwarded-for', 'x-real-ip', 'x-client-ip'];
  const detectedHeaders = suspiciousHeaders.filter(header => req.get(header));

  if (detectedHeaders.length > 0 && req.ip !== req.get('x-forwarded-for')?.split(',')[0]) {
    console.warn(`Potential rate limit bypass attempt from IP: ${req.ip}, Headers: ${JSON.stringify(detectedHeaders)}`);
  }

  next();
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

