package com.ansvar.ratelimit;

import io.github.bucket4j.Bandwidth;
import io.github.bucket4j.Bucket;
import io.github.bucket4j.BucketConfiguration;
import io.github.bucket4j.distributed.proxy.ProxyManager;
import io.github.bucket4j.redis.lettuce.cas.LettuceBasedProxyManager;
import io.lettuce.core.RedisClient;
import io.lettuce.core.api.StatefulRedisConnection;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.time.Duration;
import java.util.Arrays;
import java.util.List;
import java.util.function.Supplier;

@Configuration
public class RateLimitConfig {

    @Value("${trusted.proxy.ips}")
    private String trustedProxyIps; // e.g., "10.0.0.1,172.16.0.1"

    @Bean
    public ProxyManager<String> proxyManager(RedisClient redisClient) {
        StatefulRedisConnection<String, byte[]> connection = 
            redisClient.connect(io.lettuce.core.codec.RedisCodec.of(
                io.lettuce.core.codec.StringCodec.UTF8,
                io.lettuce.core.codec.ByteArrayCodec.INSTANCE
            ));
        return LettuceBasedProxyManager.builderFor(connection).build();
    }

    @Bean
    public List<String> trustedProxies() {
        return Arrays.asList(trustedProxyIps.split(","));
    }
}

@Component
public class RateLimitFilter extends OncePerRequestFilter {

    private final ProxyManager<String> proxyManager;
    private final List<String> trustedProxies;

    // Different rate limits for different endpoint types
    private static final BucketConfiguration API_CONFIG = BucketConfiguration.builder()
        .addLimit(Bandwidth.simple(100, Duration.ofMinutes(15))) // 100 requests per 15 minutes
        .build();

    private static final BucketConfiguration AUTH_CONFIG = BucketConfiguration.builder()
        .addLimit(Bandwidth.simple(5, Duration.ofMinutes(15))) // 5 attempts per 15 minutes
        .build();

    public RateLimitFilter(ProxyManager<String> proxyManager, List<String> trustedProxies) {
        this.proxyManager = proxyManager;
        this.trustedProxies = trustedProxies;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, 
                                    HttpServletResponse response, 
                                    FilterChain filterChain) 
            throws ServletException, IOException {

        // Extract and validate client IP
        String clientIp = getValidatedClientIp(request);

        // Determine rate limit configuration based on endpoint
        BucketConfiguration config = isAuthEndpoint(request) ? AUTH_CONFIG : API_CONFIG;
        Supplier<BucketConfiguration> configSupplier = () -> config;

        // Create unique key for this client
        String bucketKey = "rate_limit:" + clientIp + ":" + request.getRequestURI();

        // Get or create bucket for this client
        Bucket bucket = proxyManager.builder().build(bucketKey, configSupplier);

        // Try to consume a token
        if (bucket.tryConsume(1)) {
            // Add rate limit headers
            long remainingTokens = bucket.getAvailableTokens();
            response.setHeader("X-Rate-Limit-Remaining", String.valueOf(remainingTokens));
            response.setHeader("X-Rate-Limit-Limit", "100");

            filterChain.doFilter(request, response);
        } else {
            // Rate limit exceeded
            long waitForRefill = bucket.estimateAbilityToConsume(1).getNanosToWaitForRefill() / 1_000_000_000;

            response.setStatus(429);
            response.setHeader("X-Rate-Limit-Retry-After-Seconds", String.valueOf(waitForRefill));
            response.setContentType("application/json");
            response.getWriter().write(
                String.format("{\"error\":\"Too many requests\",\"retryAfter\":%d}", waitForRefill)
            );

            // Log potential abuse
            logger.warn("Rate limit exceeded for IP: " + clientIp + " on endpoint: " + request.getRequestURI());
        }
    }

    /**
     * Extract and validate client IP from request.
     * Only trusts X-Forwarded-For if request comes from a trusted proxy.
     */
    private String getValidatedClientIp(HttpServletRequest request) {
        String remoteAddr = request.getRemoteAddr();

        // If the request is NOT from a trusted proxy, use the direct connection IP
        if (!trustedProxies.contains(remoteAddr)) {
            return remoteAddr;
        }

        // Request is from trusted proxy, check X-Forwarded-For
        String xForwardedFor = request.getHeader("X-Forwarded-For");

        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            // X-Forwarded-For format: client, proxy1, proxy2
            // Take the leftmost (original client) IP
            String clientIp = xForwardedFor.split(",")[0].trim();

            // Validate IP format to prevent injection
            if (isValidIpAddress(clientIp)) {
                return clientIp;
            }
        }

        // Fallback to remote address
        return remoteAddr;
    }

    private boolean isValidIpAddress(String ip) {
        // Basic IPv4/IPv6 validation
        return ip.matches(
            "^(?:[0-9]{1,3}\\.){3}[0-9]{1,3}$|" + // IPv4
            "^(?:[a-fA-F0-9]{1,4}:){7}[a-fA-F0-9]{1,4}$" // IPv6 (simplified)
        );
    }

    private boolean isAuthEndpoint(HttpServletRequest request) {
        String uri = request.getRequestURI();
        return uri.contains("/login") || uri.contains("/register") || uri.contains("/reset-password");
    }
}
